        {nodes.map((node, i) => {
          const nodeOp = interpolate(frame, [node.delay, node.delay + 30], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const rippleScale = interpolate(frame, [node.delay, node.delay + 60], [0, 3], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
          const rippleOp = interpolate(frame, [node.delay, node.delay + 60], [0.6, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

          return (
            <g key={i} style={{ opacity: nodeOp }}>
              <circle cx={node.x} cy={node.y} r={20 * rippleScale} fill="none" stroke="#FFCC00" strokeWidth={2} style={{ opacity: rippleOp }} />
              <circle cx={node.x} cy={node.y} r={6} fill="#FFCC00" />
            </g>
          );
        })}
      </svg>

      <div style={{ position: 'absolute', top: 800, left: 192, width: 600, opacity: statOp }}>
        <div style={{ color: '#FF2222', fontSize: 64, fontWeight: 'bold', fontFamily: 'monospace' }}>{stat1}</div>
