      <div style={{ position: 'absolute', top: 800, left: 1100, width: 600, opacity: statOp, textAlign: 'right' }}>
        <div style={{ color: '#FF6600', fontSize: 64, fontWeight: 'bold', fontFamily: 'monospace' }}>{stat2}</div>
