import React, { useMemo } from 'react';
import { useCurrentFrame, useVideoConfig, interpolate } from 'remotion';

export const AnimationComponent = () => {
  const frame = useCurrentFrame();
  const { width, height } = useVideoConfig();

  const steps = useMemo(() => [
    { label: 'STOLEN KEY', desc: 'CREDENTIAL THEFT' },
    { label: 'OPEN DOOR', desc: 'UNAUTHORIZED ACCESS' },
    { label: 'LATERAL MOVE', desc: 'NETWORK PENETRATION' },
    { label: 'EXECUTION', desc: 'FACTORY RESET' },
    { label: 'SILENCE', desc: 'DATA WIPED' }
  ].filter(s => s.label !== '' && s.label !== ' '), []);

  const count = steps.length;
  const stepWidth = 280;
  const gutter = 40;
  const totalWidth = (count * stepWidth) + ((count - 1) * gutter);
  const startX = (width - totalWidth) / 2;

  return (
    <div style={{ position: 'absolute', top: 0, left: 0, width: 1920, height: 1080, overflow: 'hidden', backgroundColor: '#1A1A1A' }}>
      {steps.map((step, i) => {
        const startFrame = i * 30;
        const opacity = interpolate(frame, [startFrame, startFrame + 20], [0, 1], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const translateY = interpolate(frame, [startFrame, startFrame + 20], [40, 0], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });
        const connectorWidth = interpolate(frame, [startFrame + 15, startFrame + 40], [0, gutter], { extrapolateLeft: 'clamp', extrapolateRight: 'clamp' });

        return (
          <React.Fragment key={i}>
            <div style={{ position: 'absolute', top: 400, left: startX + (i * (stepWidth + gutter)), width: stepWidth, height: 280, opacity, transform: `translateY(${translateY}px)` }}>
              <div style={{ width: 64, height: 64, borderRadius: 32, backgroundColor: '#AAFF00', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#0A1A00', fontSize: 24, fontWeight: 'bold' }}>{i + 1}</div>
              <div style={{ marginTop: 24, fontSize: 24, fontWeight: 'bold', color: '#0A1A00', letterSpacing: '0.12em' }}>{step.label}</div>
              <div style={{ marginTop: 12, fontSize: 16, color: '#555555', lineHeight: 1.5 }}>{step.desc}</div>
            </div>
            {i < count - 1 && (
              <div style={{ position: 'absolute', top: 430, left: startX + stepWidth + (i * (stepWidth + gutter)), width: connectorWidth, height: 4, backgroundColor: '#00CCEE', opacity }} />
            )}
          </React.Fragment>
        );
      })}
    </div>
  );
};

export default AnimationComponent;
